// Parse AI response and build enrichment payload
const aiResponse = $input.first().json;
const product = $('Prepare Data').first().json.product;
const options = $('Prepare Data').first().json.options;
const callbackUrl = $('Prepare Data').first().json.callback_url;

// Extract text content from AI response
let content;
try {
  // AI may return JSON in text field
  const text = aiResponse.message?.content?.[0]?.text || aiResponse.text || JSON.stringify(aiResponse);
  // Find JSON in response
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  content = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message);
}

// Build Product schema JSON-LD
const schema = {
  "@context": "https://schema.org",
  "@type": "Product",
  "name": product.name,
  "description": content.short_description,
  "sku": product.sku,
  "image": product.image_url,
  "url": product.permalink,
  "offers": {
    "@type": "Offer",
    "price": product.price,
    "priceCurrency": "TRY",
    "availability": product.stock_status === 'instock' ? "https://schema.org/InStock" : "https://schema.org/OutOfStock",
    "url": product.permalink
  }
};

// Build callback payload
const payload = {
  product_id: product.id,
  callback_url: callbackUrl
};

if (options.generate_description) {
  payload.description = content.description;
}
if (options.generate_short_description) {
  payload.short_description = content.short_description;
}
if (options.generate_meta_title) {
  payload.meta_title = content.meta_title;
}
if (options.generate_meta_description) {
  payload.meta_description = content.meta_description;
}
if (options.generate_faq && content.faq) {
  payload.faq = content.faq;
}
if (options.generate_schema) {
  payload.schema = JSON.stringify(schema);
}
if (options.generate_alt_text && content.alt_text_main) {
  payload.alt_texts = {
    main: content.alt_text_main
  };
}
if (content.tags) {
  payload.suggested_tags = content.tags;
}

return [{ json: payload }];
